 31→@ApiTags('Auth')
 32→@Controller('auth')
 33→export class AuthController {
 34→	constructor(private readonly authService: AuthService) {}
 35→
 36→	@Public()
 37→	@Get('github')
 38→	@ApiOperation({ summary: 'Initiate GitHub OAuth' })
 39→	@ApiResponse({ status: HttpStatus.FOUND, description: 'Redirect to GitHub' })
 40→	async githubAuth(@Res() reply: FastifyReply): Promise<void> {
 41→		const url = await this.authService.initiateOAuth({ provider: 'github' });
 42→		reply.redirect(url.toString());
 43→	}
 44→
 45→	@Public()
 46→	@Get('github/callback')
 47→	@ApiOperation({ summary: 'Handle GitHub OAuth callback' })
 48→	@ApiResponse({ status: HttpStatus.FOUND, description: 'Redirect to frontend' })
 49→	async githubCallback(
 50→		@Query('code') code: string,
 51→		@Query('state') state: string,
 52→		@Res() reply: FastifyReply,
 53→	): Promise<void> {
 54→		const result = await this.authService.handleCallback({
 55→			provider: 'github',
 56→			code,
 57→			state,
 58→		});
 59→		const frontendUrl = getEnv<string>({ key: FRONTEND_URL });
 60→		if (result.type === 'auth_code') {
 61→			reply.redirect(`${frontendUrl}/auth/callback?code=${result.code}`);
 62→		} else {
 63→			reply.redirect(`${frontendUrl}/auth/link?linking_token=${result.linkingToken}`);
 64→		}
 65→	}
 66→
 67→	@Public()
 68→	@Get('google')
 69→	@ApiOperation({ summary: 'Initiate Google OAuth' })
 70→	@ApiResponse({ status: HttpStatus.FOUND, description: 'Redirect to Google' })
 71→	async googleAuth(@Res() reply: FastifyReply): Promise<void> {
 72→		const url = await this.authService.initiateOAuth({ provider: 'google' });
 73→		reply.redirect(url.toString());
 74→	}
 75→
 76→	@Public()
 77→	@Get('google/callback')
 78→	@ApiOperation({ summary: 'Handle Google OAuth callback' })
 79→	@ApiResponse({ status: HttpStatus.FOUND, description: 'Redirect to frontend' })
 80→	async googleCallback(
 81→		@Query('code') code: string,
 82→		@Query('state') state: string,
 83→		@Res() reply: FastifyReply,
 84→	): Promise<void> {
 85→		const result = await this.authService.handleCallback({
 86→			provider: 'google',
 87→			code,
 88→			state,
 89→		});
 90→		const frontendUrl = getEnv<string>({ key: FRONTEND_URL });
 91→		if (result.type === 'auth_code') {
 92→			reply.redirect(`${frontendUrl}/auth/callback?code=${result.code}`);
