import { ForbiddenException, NotFoundException } from '@nestjs/common';
import { Test, TestingModule } from '@nestjs/testing';

import { IRequestUser } from '@modules/auth/types/auth.interface';
import { CompanyMemberService } from '@modules/company-member/company-member.service';
import { CompanyController } from '@modules/company/company.controller';
import { CompanyService } from '@modules/company/company.service';
import { ICompanyBase } from '@modules/company/types/company.base.interface';

const mockCompanyService = {
	findById: jest.fn(),
};

const mockCompanyMemberService = {
	findByUserAndCompany: jest.fn(),
};

const mockUser: IRequestUser = {
	user_id: 'user-123',
	session_id: 'session-456',
	role: 'member',
	company_id: 'company-abc',
};

const mockCompany: ICompanyBase = {
	_id: 'company-abc',
	name: 'Acme Corp',
	created_at: new Date('2024-01-01'),
	updated_at: new Date('2024-01-01'),
	deleted_at: null,
};

const mockMembership = {
	_id: 'member-1',
	user_id: 'user-123',
	company_id: 'company-abc',
	role: 'member',
	created_at: new Date('2024-01-01'),
	updated_at: new Date('2024-01-01'),
	deleted_at: null,
};

describe('CompanyController', () => {
	let controller: CompanyController;

	beforeEach(async () => {
		jest.clearAllMocks();

		const module: TestingModule = await Test.createTestingModule({
			controllers: [CompanyController],
			providers: [
				{ provide: CompanyService, useValue: mockCompanyService },
				{ provide: CompanyMemberService, useValue: mockCompanyMemberService },
			],
		}).compile();

		controller = module.get<CompanyController>(CompanyController);
	});

	afterEach(() => jest.clearAllMocks());

	it('should be defined', () => {
		expect(controller).toBeDefined();
	});

	describe('getById', () => {
		it('should return company when user is a member', async () => {
			mockCompanyMemberService.findByUserAndCompany.mockResolvedValue(mockMembership);
			mockCompanyService.findById.mockResolvedValue(mockCompany);

			const result = await controller.getById('company-abc', mockUser);

			expect(mockCompanyMemberService.findByUserAndCompany).toHaveBeenCalledWith({
				userId: 'user-123',
				companyId: 'company-abc',
			});
			expect(mockCompanyService.findById).toHaveBeenCalledWith({
				companyId: 'company-abc',
			});
			expect(result).toEqual(mockCompany);
		});

		it('should throw ForbiddenException when user is not a member', async () => {
			mockCompanyMemberService.findByUserAndCompany.mockResolvedValue(null);

			await expect(controller.getById('company-abc', mockUser)).rejects.toThrow(
				ForbiddenException,
			);

			expect(mockCompanyService.findById).not.toHaveBeenCalled();
		});

		it('should throw NotFoundException when company is not found', async () => {
			mockCompanyMemberService.findByUserAndCompany.mockResolvedValue(mockMembership);
			mockCompanyService.findById.mockResolvedValue(null);

			await expect(controller.getById('company-abc', mockUser)).rejects.toThrow(
				NotFoundException,
			);
		});
	});
});
